#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int K, N;
    cin >> K >> N;

    // Convert K to 0-based row and column
    // The board is numbered row by row from top-left:
    // row = (K-1) / N, col = (K-1) % N
    int r = (K - 1) / N;
    int c = (K - 1) % N;

    vector<int> neighbors;

    // Top neighbor
    if (r > 0) {
        int top = (r - 1) * N + c + 1;
        neighbors.push_back(top);
    }
    // Right neighbor
    if (c + 1 < N) {
        int right = r * N + (c + 1) + 1;
        neighbors.push_back(right);
    }
    // Bottom neighbor
    if (r + 1 < N) {
        int bottom = (r + 1) * N + c + 1;
        neighbors.push_back(bottom);
    }
    // Left neighbor
    if (c > 0) {
        int left = r * N + (c - 1) + 1;
        neighbors.push_back(left);
    }

    for (size_t i = 0; i < neighbors.size(); ++i) {
        if (i > 0) cout << ' ';
        cout << neighbors[i];
    }
    cout << '\n';

    return 0;
}
